// Fix the bug by sorting the media queries in ascending order of their width
function fixMediaQueries(css) {
  var queries = css.match(/@media (min|max)-width: ([0-9]+)px/g);
  queries.sort(function(a, b) {
    return parseInt(a[2]) - parseInt(b[2]);
  });
  return css.split('@media').sort(function(a, b) {
    var aWidth = a.match(/(min|max)-width: ([0-9]+)px/)[2];
    var bWidth = b.match(/(min|max)-width: ([0-9]+)px/)[2];
    return parseInt(aWidth) - parseInt(bWidth);
  }).join('@media');
}

solutions.python:
import re

def fix_media_queries(css) -> str:
  queries = re.findall(r'@media (min|max)-width: ([0-9]+)px', css)
  queries.sort(key=lambda x: int(x[1]))
  sorted_css = ''
  for query in sorted(queries, key=lambda x: int(x[1]), reverse=True):
    sorted_css += query + css[css.find(query) + len(query):]
  return sorted_css.replace('\n', '').replace('\t', '')

